      { id: 'construction_material', label: 'Construction Material', icon: '🏗️' },
      { id: 'machinery', label: 'Machinery', icon: '🔩' },
      { id: 'chemicals', label: 'Chemicals', icon: '🧪' },
      { id: 'oil_fuel', label: 'Oil / Fuel', icon: '🛢️' },
      { id: 'tyres', label: 'Tyres / Auto Parts', icon: '🔧' },
